        # Parse the series string format
        # Expected format: "timestamps: [t1, t2, ...]; values: [v1, v2, ...]"
        parts = s.split(";")
        timestamps = []
        values = []
        for part in parts:
            part = part.strip()
            if part.startswith("timestamps:"):
                ts_str = part[len("timestamps:"):].strip()
                # Remove brackets and parse
                ts_str = ts_str.strip("[]")
                if ts_str:
                    timestamps = [int(x.strip()) for x in ts_str.split(",")]
            elif part.startswith("values:"):
                val_str = part[len("values:"):].strip()
                val_str = val_str.strip("[]")
                if val_str:
                    values = [float(x.strip()) for x in val_str.split(",")]
        parsed_series.append({"timestamps": timestamps, "values": values})

    # Merge all series: later series in the list win on timestamp conflicts
    # (i.e., process in order, later entries overwrite earlier ones)
    merged: dict[int, float] = {}
    for series in parsed_series:
        for ts, value in zip(series["timestamps"], series["values"]):
