def forecast_next_zero(series: dict[str, Any], method: str = "last") -> float:
    """Forecast using the specified method."""
    if not series["values"]:
        return 0.0
    if method == "last":
        return series["values"][-1]
    elif method == "mean":
        return sum(series["values"]) / len(series["values"])
    elif method == "diff":
        if len(series["values"]) < 2:
            return 0.0
        last_diff = series["values"][-1] - series["values"][-2]
        return series["values"][-1] + last_diff
    else:
        return 0.0


